// Active-equity universe for the stock-mover leaderboard (v2: Nifty 500).
//
// Primary universe: the real Nifty 500 constituents, served from a committed snapshot
// (lib/maven/data/nifty500.json, generated by scripts/gen-nifty500.mjs from NSE's published,
// DOWNLOADABLE index-constituents CSV on nsearchives - the same permitted-file pattern
// nseUniverse.ts uses, not website scraping). A best-effort in-memory refresh (daily TTL) keeps
// constituents current where the fetch is reachable; on Vercel (datacenter IPs often blocked by
// NSE) the snapshot serves. Nifty 500 is EQ-series equities by construction - no ETFs, REITs,
// InvITs, indices, warrants or debt. Fallback: the v1 curated liquid list. Never fabricated.

import nifty500 from "./data/nifty500.json";

export type UniverseCoverage = "curated_liquid" | "nifty500" | "broad_liquid_nse" | "full_nse_attempted";

export type ActiveEquityUniverse = {
  symbols: { symbol: string; name: string }[];
  universeLabel: string;
  universeSize: number;
  coverage: UniverseCoverage;
  limitation?: string;
};

const N500_URL = "https://nsearchives.nseindia.com/content/indices/ind_nifty500list.csv";
const UA = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36";
const REFRESH_TTL = 24 * 60 * 60 * 1000;

type RawConstituent = { s: string; n: string; industry?: string };
let N500: { symbol: string; name: string }[] =
  ((nifty500 as any).constituents as RawConstituent[]).map((c) => ({ symbol: c.s, name: c.n }));
let lastRefresh = 0;

// Best-effort constituents refresh from the permitted downloadable CSV; snapshot serves on failure.
async function refreshNifty500(): Promise<void> {
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 8000);
  try {
    const r = await fetch(N500_URL, { headers: { "User-Agent": UA, Accept: "text/csv,*/*" }, signal: ctrl.signal, cache: "no-store" });
    if (!r.ok) return;
    const lines = (await r.text()).trim().split(/\r?\n/);
    const next: { symbol: string; name: string }[] = [];
    for (const line of lines.slice(1)) {
      const c = line.split(",").map((x) => x.trim());
      if (c.length < 5 || !c[2]) continue;
      if ((c[3] || "EQ").toUpperCase() !== "EQ") continue; // normal equity series only
      next.push({ symbol: c[2], name: c[0] });
    }
    if (next.length >= 400) { N500 = next; lastRefresh = Date.now(); }
  } catch {
    /* unreachable (e.g. datacenter IP blocked) -> keep committed snapshot, no user-facing error */
  } finally {
    clearTimeout(timer);
  }
}

