/**
 * The active-equity universe the mover scanner ranks within.
 * v2 primary: real Nifty 500 constituents (committed snapshot + best-effort daily refresh).
 * Fallback: the v1 curated liquid list (only if the snapshot is somehow unusable).
 */
export async function getActiveEquityUniverse(): Promise<ActiveEquityUniverse> {
  if (Date.now() - lastRefresh > REFRESH_TTL) void refreshNifty500(); // fire-and-forget; snapshot serves immediately
  if (N500.length >= 400) {
    return {
      symbols: N500,
      universeLabel: "Nifty 500",
      universeSize: N500.length,
      coverage: "nifty500",
      limitation: undefined, // coverage wording is added by the scanner with real scan counts
    };
  }
  return {
    symbols: CURATED,
    universeLabel: "curated liquid NSE equities",
    universeSize: CURATED.length,
    coverage: "curated_liquid",
    limitation: "Ranked within a curated liquid NSE-equity universe, not the full NSE list.",
  };
}
